import{h as e,am as i,f as a}from"./vue-vendor-BNGP8MTa.js";const l={class:"py-12"},n={__name:"DeveloperPolicy",setup(r){return(s,t)=>(a(),e("div",l,[...t[0]||(t[0]=[i('<div class="w-full px-4 sm:px-6 md:px-8 lg:px-12 xl:px-16"><div class="max-w-4xl mx-auto"><h1 class="text-4xl font-bold text-gray-900 dark:text-white mb-8">Developer Policy</h1><div class="prose prose-lg dark:prose-invert max-w-none"><p class="text-gray-600 dark:text-gray-400 mb-6"> Last updated: April 21, 2026 </p><h2 class="text-2xl font-semibold text-gray-900 dark:text-white mt-8 mb-4">1. Developer Account Requirements</h2><p class="text-gray-600 dark:text-gray-400 mb-4"> To become a developer on the Frappe App Store, you must: </p><ul class="list-disc list-inside text-gray-600 dark:text-gray-400 mb-4"><li>Be at least 18 years old</li><li>Have a valid email address</li><li>Provide accurate and complete profile information</li><li>Agree to comply with this Developer Policy</li></ul><h2 class="text-2xl font-semibold text-gray-900 dark:text-white mt-8 mb-4">2. Application Submission Guidelines</h2><p class="text-gray-600 dark:text-gray-400 mb-4"> All applications submitted to the Frappe App Store must: </p><ul class="list-disc list-inside text-gray-600 dark:text-gray-400 mb-4"><li>Be fully functional and free of critical bugs</li><li>Include clear and accurate documentation</li><li>Comply with Frappe framework standards</li><li>Have a valid license (MIT, GPL, or commercial)</li><li>Include appropriate screenshots and descriptions</li><li>Not contain malware or malicious code</li><li>Respect user privacy and data security</li></ul><h2 class="text-2xl font-semibold text-gray-900 dark:text-white mt-8 mb-4">3. Code of Conduct</h2><p class="text-gray-600 dark:text-gray-400 mb-4"> Developers agree to: </p><ul class="list-disc list-inside text-gray-600 dark:text-gray-400 mb-4"><li>Maintain professional communication with users and support staff</li><li>Respond to support requests within a reasonable timeframe</li><li>Not engage in fraudulent or deceptive practices</li><li>Not attempt to manipulate ratings or reviews</li><li>Respect intellectual property rights of others</li></ul><h2 class="text-2xl font-semibold text-gray-900 dark:text-white mt-8 mb-4">4. Application Maintenance</h2><p class="text-gray-600 dark:text-gray-400 mb-4"> Developers are responsible for: </p><ul class="list-disc list-inside text-gray-600 dark:text-gray-400 mb-4"><li>Keeping applications updated and compatible with latest Frappe versions</li><li>Fixing bugs and security vulnerabilities in a timely manner</li><li>Providing clear release notes for updates</li><li>Maintaining backward compatibility when possible</li></ul><h2 class="text-2xl font-semibold text-gray-900 dark:text-white mt-8 mb-4">5. Revenue and Payments</h2><p class="text-gray-600 dark:text-gray-400 mb-4"> Revenue from paid applications is distributed according to our revenue sharing model. Payments are processed monthly, subject to a minimum threshold. </p><h2 class="text-2xl font-semibold text-gray-900 dark:text-white mt-8 mb-4">6. Application Removal</h2><p class="text-gray-600 dark:text-gray-400 mb-4"> We reserve the right to remove applications from the store for: </p><ul class="list-disc list-inside text-gray-600 dark:text-gray-400 mb-4"><li>Violation of this Developer Policy</li><li>Security vulnerabilities or malware</li><li>Copyright or trademark infringement</li><li>Fraudulent or deceptive practices</li><li>Failure to maintain the application</li></ul><h2 class="text-2xl font-semibold text-gray-900 dark:text-white mt-8 mb-4">7. Intellectual Property</h2><p class="text-gray-600 dark:text-gray-400 mb-4"> Developers retain ownership of their applications but grant us a license to distribute and display them on the Frappe App Store. </p><h2 class="text-2xl font-semibold text-gray-900 dark:text-white mt-8 mb-4">8. Support Requirements</h2><p class="text-gray-600 dark:text-gray-400 mb-4"> Developers must provide reasonable support for their applications, including: </p><ul class="list-disc list-inside text-gray-600 dark:text-gray-400 mb-4"><li>Documentation and user guides</li><li>Bug reporting and issue tracking</li><li>Response to user inquiries within 48 hours</li><li>Regular updates and maintenance</li></ul><h2 class="text-2xl font-semibold text-gray-900 dark:text-white mt-8 mb-4">9. Verification Badge</h2><p class="text-gray-600 dark:text-gray-400 mb-4"> The verified developer badge is awarded to developers who meet our quality standards and maintain a good track record on the platform. Verification may be revoked for policy violations. </p><h2 class="text-2xl font-semibold text-gray-900 dark:text-white mt-8 mb-4">10. Policy Violations</h2><p class="text-gray-600 dark:text-gray-400 mb-4"> Violations of this policy may result in: </p><ul class="list-disc list-inside text-gray-600 dark:text-gray-400 mb-4"><li>Warning or notice</li><li>Temporary suspension of developer account</li><li>Permanent removal from the platform</li><li>Legal action if necessary</li></ul><h2 class="text-2xl font-semibold text-gray-900 dark:text-white mt-8 mb-4">11. Contact</h2><p class="text-gray-600 dark:text-gray-400 mb-4"> For questions about this Developer Policy, please contact us at developers@frappe.io </p></div></div></div>',1)])]))}};export{n as default};
